"use client"

import { useState, useCallback, use } from "react"
import { callProposalGeneratorAction } from "@/app/actions/severino"
import { useRouter } from "next/navigation"
import Link from "next/link"
import { useBreadcrumbSetter } from "@/hooks/use-breadcrumb-setter"
import { Download, Target } from "lucide-react"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { useProposals } from "@/contexts/proposals-context"
import { useProjects } from "@/contexts/projects-context"
import { useLeads } from "@/contexts/leads-context"
import { ProposalChatPanel } from "@/components/proposal-chat-panel"
import { ProposalDocument } from "@/components/proposal-document"
import type { ProposalMessage, ProposalInteresse, ProposalModelo } from "@/lib/proposal-types"

const interesseOptions: ProposalInteresse[] = ["Vazio", "Software", "Aplicativo", "Alocacao", "IA"]
const modeloOptions: ProposalModelo[] = ["Vazio", "Escopo Fechado", "Squad Gerenciado", "Body Shop"]

function parseMarkdownToSections(
  markdown: string
): { key: string; title: string; content: string }[] {
  const sections: { key: string; title: string; content: string }[] = []
  const lines = markdown.split("\n")
  let currentTitle = ""
  let currentContent: string[] = []

  for (const line of lines) {
    const h2Match = line.match(/^##\s+(.+)$/)
    const h1Match = line.match(/^#\s+(.+)$/)

    if (h2Match || h1Match) {
      if (currentTitle) {
        const key = currentTitle
          .toLowerCase()
          .normalize("NFD")
          .replace(/[\u0300-\u036f]/g, "")
          .replace(/[^a-z0-9]+/g, "-")
          .replace(/^-|-$/g, "")
        sections.push({ key, title: currentTitle, content: currentContent.join("\n").trim() })
      }
      currentTitle = (h2Match || h1Match)![1].trim()
      currentContent = []
    } else {
      currentContent.push(line)
    }
  }

  if (currentTitle) {
    const key = currentTitle
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-|-$/g, "")
    sections.push({ key, title: currentTitle, content: currentContent.join("\n").trim() })
  }

  return sections
}


export default function ProposalEditorPage({
  params,
}: {
  params: Promise<{ id: string }>
}) {
  const { id } = use(params)
  const router = useRouter()
  const {
    getProposal,
    addMessage,
    setProposalContent,
    updateProposal,
  } = useProposals()

  const { projects, addProject, addKnowledgeBaseFile } = useProjects()
  const { leads } = useLeads()

  const proposal = getProposal(id)

  useBreadcrumbSetter([
    { label: "Gerador de Proposta", href: "/dashboard/gerador-de-proposta" },
    { label: proposal?.nome ?? "Proposta" },
  ])

  const [isProcessing, setIsProcessing] = useState(false)
  const [highlightedSections, setHighlightedSections] = useState<Set<string>>(new Set())
  const [activeTab, setActiveTab] = useState<"chat" | "proposta">("chat")

  const empresa = proposal?.empresa ?? ""
  const para = proposal?.para ?? ""
  const projeto = proposal?.projeto ?? ""
  const interesse = proposal?.interesse ?? "Vazio"
  const modeloTrabalho = proposal?.modeloTrabalho ?? "Vazio"

  // Find linked lead
  const leadOrigem = proposal?.leadOrigemId
    ? leads.find((l) => l.id === proposal.leadOrigemId)
    : undefined

  const handleSendMessage = useCallback(
    async (content: string, fileName?: string) => {
      if (!proposal) return

      const userMsg: ProposalMessage = {
        id: `user-${Date.now()}`,
        role: "user",
        content,
        fileName,
      }
      addMessage(id, userMsg)
      setIsProcessing(true)

      const contextParts: string[] = []
      if (para) contextParts.push(`Cliente: ${para}`)
      if (empresa) contextParts.push(`Empresa: ${empresa}`)
      if (projeto) contextParts.push(`Projeto: ${projeto}`)
      if (interesse && interesse !== "Vazio") contextParts.push(`Interesse/Tipo: ${interesse}`)
      if (modeloTrabalho && modeloTrabalho !== "Vazio") contextParts.push(`Modelo: ${modeloTrabalho}`)
      const context = contextParts.join("\n")

      const apiMessages = [
        ...proposal.conversationHistory.map((m) => ({
          role: m.role,
          content: m.content,
        })),
        { role: "user" as const, content },
      ]

      try {
        const data = await callProposalGeneratorAction({ context, messages: apiMessages, lead_id: proposal.leadOrigemId })

        const aiContent = data.assistant_message || "Resposta recebida."
        const sections = parseMarkdownToSections(aiContent)

        if (data.is_proposal_ready && sections.length > 0) {
          setProposalContent(id, sections)
          const keys = sections.map((s) => s.key)
          setHighlightedSections(new Set(keys))
          setTimeout(() => setHighlightedSections(new Set()), 2000)
          setActiveTab("proposta")

          addMessage(id, {
            id: `ai-${Date.now()}`,
            role: "assistant",
            content: "✅ Proposta comercial gerada com sucesso! Confira o documento ao lado.",
          })
        } else {
          addMessage(id, {
            id: `ai-${Date.now()}`,
            role: "assistant",
            content: aiContent,
          })
        }
      } catch (error) {
        console.error("[proposal-generator] Error:", error)
        addMessage(id, {
          id: `ai-error-${Date.now()}`,
          role: "assistant",
          content: "Desculpe, ocorreu um erro ao processar sua mensagem. Tente novamente.",
        })
      } finally {
        setIsProcessing(false)
      }
    },
    [id, proposal, empresa, para, projeto, interesse, modeloTrabalho, addMessage, setProposalContent]
  )

  function handleMarkConcluida() {
    updateProposal(id, { status: "Concluída" })
    toast.success("Proposta marcada como concluída!")
  }

  function generateJiraKey(name: string): string {
    const words = name.split(/\s+/).filter(Boolean)
    let key = words.map((w) => w[0]?.toUpperCase()).join("")
    if (!key) key = "PRJ"
    const existingKeys = projects.map((p) => p.jiraKey)
    if (!existingKeys.includes(key)) return key
    let i = 2
    while (existingKeys.includes(`${key}${i}`)) i++
    return `${key}${i}`
  }

  function handleAprovar() {
    if (!proposal) return
    const jiraKey = generateJiraKey(empresa)
    const newProject = addProject({
      name: empresa,
      jiraKey,
      status: "Ativo",
      baseConhecimento: [],
    })
    const sanitizedName = empresa.replace(/\s+/g, "_")
    addKnowledgeBaseFile(newProject.id, {
      id: `kb-prop-${Date.now()}`,
      nome: `Proposta_Comercial_${sanitizedName}.pdf`,
      tipo: ".pdf",
      tamanho: "256 KB",
      dataUpload: Date.now(),
      enviadoPor: "João Silva",
      origem: "Proposta Comercial",
      conteudo: JSON.stringify(proposal.proposalContent),
    })
    updateProposal(id, {
      status: "Aprovada",
      projetoGeradoId: newProject.id,
    })
    toast.success(`Proposta aprovada com sucesso! O projeto "${empresa}" foi criado e a proposta adicionada a base de conhecimento.`)
  }

  if (!proposal) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <div className="text-center">
          <p className="text-sm text-muted-foreground">Proposta não encontrada.</p>
          <Button
            variant="link"
            onClick={() => router.push("/dashboard/gerador-de-proposta")}
            className="mt-2 text-primary"
          >
            Voltar para listagem
          </Button>
        </div>
      </div>
    )
  }

  const projetoGerado = proposal.projetoGeradoId
    ? projects.find((p) => p.id === proposal.projetoGeradoId)
    : undefined

  return (
    <div className="flex flex-1 flex-col gap-4 overflow-hidden">
      {/* Top bar with fields */}
      <div className="flex flex-col gap-3">
        {/* Row 1: Para + Empresa + Projeto */}
        <div className="grid grid-cols-1 gap-3 sm:grid-cols-3">
          <div>
            <Label htmlFor="editor-para" className="text-xs font-medium text-muted-foreground">
              Para (Nome do Cliente)
            </Label>
            <Input
              id="editor-para"
              value={para}
              onChange={(e) => updateProposal(id, { para: e.target.value })}
              placeholder="Nome do cliente"
              className="mt-1"
            />
          </div>
          <div>
            <Label htmlFor="editor-empresa" className="text-xs font-medium text-muted-foreground">
              Empresa
            </Label>
            <Input
              id="editor-empresa"
              value={empresa}
              onChange={(e) => updateProposal(id, { empresa: e.target.value })}
              placeholder="Nome da empresa"
              className="mt-1"
            />
          </div>
          <div>
            <Label htmlFor="editor-projeto" className="text-xs font-medium text-muted-foreground">
              Projeto
            </Label>
            <Input
              id="editor-projeto"
              value={projeto}
              onChange={(e) => updateProposal(id, { projeto: e.target.value })}
              placeholder="Nome do projeto"
              className="mt-1"
            />
          </div>
        </div>
        {/* Row 2: Interesse + Modelo */}
        <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
          <div>
            <Label className="text-xs font-medium text-muted-foreground">Interesse</Label>
            <Select
              value={interesse}
              onValueChange={(val) => updateProposal(id, { interesse: val as ProposalInteresse })}
            >
              <SelectTrigger className="mt-1">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {interesseOptions.map((opt) => (
                  <SelectItem key={opt} value={opt}>{opt === "Vazio" ? "Não definido" : opt}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
          <div>
            <Label className="text-xs font-medium text-muted-foreground">Modelo de Trabalho</Label>
            <Select
              value={modeloTrabalho}
              onValueChange={(val) => updateProposal(id, { modeloTrabalho: val as ProposalModelo })}
            >
              <SelectTrigger className="mt-1">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {modeloOptions.map((opt) => (
                  <SelectItem key={opt} value={opt}>{opt === "Vazio" ? "Não definido" : opt}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </div>
      </div>

      {/* Lead link banner */}
      {leadOrigem && (
        <div className="flex items-center gap-3 rounded-lg bg-secondary px-4 py-3">
          <Target className="h-4 w-4 shrink-0 text-primary" />
          <p className="text-sm text-primary">
            {"Esta proposta foi gerada a partir do lead "}
            <strong>{`"${leadOrigem.titulo}"`}</strong>.{" "}
            <Link
              href="/dashboard/leads"
              className="font-medium underline underline-offset-2 hover:text-primary/90"
            >
              Ver Lead
            </Link>
          </p>
        </div>
      )}

      {/* Mobile tab switcher */}
      <div className="flex gap-1 rounded-lg bg-muted p-1 lg:hidden">
        <Button
          variant={activeTab === "chat" ? "secondary" : "ghost"}
          onClick={() => setActiveTab("chat")}
          className={`flex-1 rounded-md px-3 py-1.5 text-sm font-medium ${
            activeTab === "chat"
              ? "bg-card text-foreground shadow-sm"
              : "text-muted-foreground hover:text-foreground"
          }`}
        >
          Assistente
        </Button>
        <Button
          variant={activeTab === "proposta" ? "secondary" : "ghost"}
          onClick={() => setActiveTab("proposta")}
          className={`flex-1 rounded-md px-3 py-1.5 text-sm font-medium ${
            activeTab === "proposta"
              ? "bg-card text-foreground shadow-sm"
              : "text-muted-foreground hover:text-foreground"
          }`}
        >
          Proposta
        </Button>
      </div>

      {/* Desktop: 50/50 split */}
      <div className="flex flex-1 gap-4 overflow-hidden">
        <div
          className={`flex-1 overflow-hidden lg:flex lg:max-w-none ${
            activeTab === "chat" ? "flex" : "hidden lg:flex"
          }`}
          style={{ flex: "1 1 50%" }}
        >
          <div className="flex w-full flex-col overflow-hidden md:flex-[45] lg:flex-[50]">
            <ProposalChatPanel
              messages={proposal.conversationHistory}
              onSendMessage={handleSendMessage}
              isProcessing={isProcessing}
            />
          </div>
        </div>

        <div
          className={`flex-1 overflow-hidden lg:flex lg:max-w-none ${
            activeTab === "proposta" ? "flex" : "hidden lg:flex"
          }`}
          style={{ flex: "1 1 50%" }}
        >
          <div className="flex w-full flex-col overflow-hidden md:flex-[55] lg:flex-[50]">
            <ProposalDocument
              empresa={empresa}
              para={para}
              projeto={projeto}
              proposalNumber={proposal.proposalNumber}
              dataCriacao={proposal.dataCriacao}
              sections={proposal.proposalContent}
              highlightedSections={highlightedSections}
              status={proposal.status}
              interesse={interesse}
              modeloTrabalho={modeloTrabalho}
              projetoGeradoId={proposal.projetoGeradoId}
              projetoGeradoNome={projetoGerado?.name}
              onMarkConcluida={handleMarkConcluida}
              onAprovar={handleAprovar}
            />
          </div>
        </div>
      </div>

      {activeTab === "proposta" && proposal.proposalContent.length > 0 && (
        <div className="fixed bottom-4 left-1/2 z-30 -translate-x-1/2 lg:hidden">
          <Button
            className="bg-primary text-primary-foreground shadow-lg hover:bg-primary/90"
            size="default"
          >
            <Download className="mr-2 h-4 w-4" />
            Baixar PDF
          </Button>
        </div>
      )}
    </div>
  )
}

"use client"

import { useState, useRef } from "react"
import { Download, Loader2, FileText, CheckCircle, Check, Link2 } from "lucide-react"
import { toast } from "sonner"
import Link from "next/link"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { cn } from "@/lib/utils"
import { MarkdownRenderer } from "@/components/markdown-renderer"
import type { ProposalSection, ProposalStatus, ProposalInteresse, ProposalModelo } from "@/lib/proposal-types"
import { formatDateShort } from "@/lib/proposal-types"
import { buildProposalTokens } from "@/lib/proposal-pdf-utils"

interface ProposalDocumentProps {
  empresa: string
  para?: string
  projeto?: string
  proposalNumber: string
  dataCriacao: number
  sections: ProposalSection[]
  highlightedSections: Set<string>
  status: ProposalStatus
  interesse?: ProposalInteresse
  modeloTrabalho?: ProposalModelo
  projetoGeradoId?: string
  projetoGeradoNome?: string
  onMarkConcluida?: () => void
  onAprovar?: () => void
}

export function ProposalDocument({
  empresa,
  para,
  projeto,
  proposalNumber,
  dataCriacao,
  sections,
  highlightedSections,
  status,
  interesse,
  modeloTrabalho,
  projetoGeradoId,
  projetoGeradoNome,
  onMarkConcluida,
  onAprovar,
}: ProposalDocumentProps) {
  const [downloading, setDownloading] = useState(false)
  const [approveOpen, setApproveOpen] = useState(false)
  const documentRef = useRef<HTMLDivElement>(null)

  async function handleDownloadPDF() {
    if (sections.length === 0) return
    setDownloading(true)
    try {
      // 1. Busca o template HTML (1.8MB com imagens em base64 embutidas)
      const res = await fetch("/proposta-template.html")
      if (!res.ok) throw new Error("Template não encontrado")
      let html = await res.text()

      // 2. Constrói os tokens a partir das seções geradas pela IA
      const tokens = buildProposalTokens({ empresa, para, projeto, modeloTrabalho, dataCriacao, sections })

      // 3. Substitui todos os tokens no HTML
      for (const [key, value] of Object.entries(tokens)) {
        html = html.replaceAll(`{{${key}}}`, value)
      }

      // 4. Abre em nova janela e dispara impressão automaticamente
      const win = window.open("", "_blank")
      if (!win) {
        toast.error("Pop-up bloqueado. Permita pop-ups para este site e tente novamente.")
        return
      }
      win.document.open()
      win.document.write(html)
      win.document.close()
      // Aguarda carregamento completo antes de imprimir
      win.addEventListener("load", () => win.print())
      setTimeout(() => { if (win && !win.closed) win.print() }, 800)

      toast.success("Proposta aberta! Selecione 'Salvar como PDF' com margens 'Nenhuma'.")
    } catch (err) {
      console.error("[ProposalDocument] PDF error:", err)
      toast.error("Erro ao gerar o PDF.")
    } finally {
      setDownloading(false)
    }
  }

  function getStatusBadge() {
    switch (status) {
      case "Aprovada":
        return <Badge variant="default">Aprovada</Badge>
      case "Concluída":
        return <Badge variant="secondary" className="bg-green-100 text-green-700 hover:bg-green-100">Concluída</Badge>
      case "Rascunho":
      default:
        return <Badge variant="outline" className="bg-yellow-50 text-yellow-700 hover:bg-yellow-50">Rascunho</Badge>
    }
  }

  return (
    <div className="flex h-full flex-col rounded-lg border border-border bg-card shadow-sm">
      {/* Header */}
      <div className="flex flex-wrap items-center justify-between gap-2 border-b border-border px-4 py-3">
        <div className="flex items-center gap-2">
          <h2 className="text-sm font-semibold text-foreground">Proposta Comercial</h2>
          {sections.length > 0 && getStatusBadge()}
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <Button
            variant="outline"
            size="sm"
            onClick={handleDownloadPDF}
            disabled={downloading || sections.length === 0}
            className="text-primary border-primary/30 hover:bg-secondary"
          >
            {downloading ? (
              <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
            ) : (
              <Download className="mr-1.5 h-3.5 w-3.5" />
            )}
            Imprimir / Salvar PDF
          </Button>
          {/* Mark as Concluida - visible when Rascunho and has content */}
          {status === "Rascunho" && sections.length > 0 && onMarkConcluida && (
            <Button
              variant="outline"
              size="sm"
              onClick={onMarkConcluida}
              className="border-[#16a34a]/30 text-[#16a34a] hover:bg-[#dcfce7]"
            >
              <CheckCircle className="mr-1.5 h-3.5 w-3.5" />
              Marcar como Concluída
            </Button>
          )}
          {/* Aprovar Proposta - visible when Concluída */}
          {status === "Concluída" && onAprovar && (
            <Button
              size="sm"
              onClick={() => setApproveOpen(true)}
              className="bg-[#16a34a] text-primary-foreground hover:bg-[#15803d]"
            >
              <CheckCircle className="mr-1.5 h-3.5 w-3.5" />
              Aprovar Proposta
            </Button>
          )}
        </div>
      </div>

      {/* Approved info banner */}
      {status === "Aprovada" && projetoGeradoId && (
        <div className="flex items-center gap-3 border-b border-border bg-secondary px-4 py-3">
          <Link2 className="h-4 w-4 shrink-0 text-primary" />
          <p className="text-sm text-primary">
            {"Esta proposta foi aprovada e gerou o projeto "}
            <strong>{`"${projetoGeradoNome || ""}"`}</strong>.{" "}
            <Link href={`/dashboard/projetos/${projetoGeradoId}`} className="font-medium underline underline-offset-2 hover:text-primary/90">
              Ver Projeto
            </Link>
          </p>
        </div>
      )}

      {/* Document content */}
      <div ref={documentRef} className="flex-1 overflow-y-auto p-4 lg:p-6">
        {sections.length === 0 ? (
          <div className="flex h-full flex-col items-center justify-center rounded-lg border-2 border-dashed border-border p-6 text-center">
            <FileText className="mb-3 h-12 w-12 text-muted-foreground/40" />
            <p className="text-sm font-medium text-muted-foreground">
              A proposta sera gerada aqui conforme voce fornecer informacoes ao assistente.
            </p>
            <p className="mt-1 text-xs text-muted-foreground">
              Comece a conversa ao lado!
            </p>
          </div>
        ) : (
          <div className="mx-auto max-w-[700px] rounded-lg border border-border bg-card p-4 shadow-md lg:p-8">
            {/* Document Header */}
            <div className="mb-6 border-b border-border pb-6">
              <div className="mb-4 text-center">
                <h1 className="text-base font-extrabold uppercase tracking-widest text-primary lg:text-lg">
                  PROPOSTA COMERCIAL — PROJETO SOB MEDIDA
                </h1>
                {modeloTrabalho && modeloTrabalho !== "Vazio" && (
                  <p className="mt-1.5 text-[11px] font-semibold uppercase tracking-widest text-primary/70">
                    MODELO DE CONTRATAÇÃO: {modeloTrabalho.toUpperCase()}
                  </p>
                )}
              </div>
              <div className="mx-auto mb-4 h-px w-16 bg-primary/30" />
              <div className="grid grid-cols-2 gap-x-6 gap-y-1.5">
                {[
                  ["PARA", para || "—"],
                  ["EMPRESA", empresa || "—"],
                  ["PROJETO", projeto || "—"],
                  ["DATA", formatDateShort(dataCriacao)],
                  ["VALIDADE", "30 dias"],
                  ["PROPOSTA Nº", `WA-${proposalNumber}`],
                ].map(([label, value]) => (
                  <div key={label} className="flex gap-1.5 text-xs lg:text-sm">
                    <span className="min-w-[90px] shrink-0 font-bold text-foreground">{label}:</span>
                    <span className="text-foreground/70">{value}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Sections */}
            <div className="flex flex-col gap-6">
              {sections.map((section) => (
                <div
                  key={section.key}
                  className={cn(
                    "rounded-md px-3 py-2 transition-colors",
                    highlightedSections.has(section.key) && "section-highlight"
                  )}
                >
                  <h2 className="mb-3 border-b border-border/60 pb-1.5 text-sm font-bold text-primary lg:text-base">
                    {section.title}
                  </h2>
                  <MarkdownRenderer
                    content={section.content
                      .split("\n")
                      .filter((l) => {
                        const t = l.trim()
                        if (/^-{1,3}$/.test(t)) return false
                        if (/^[-*•✅❌]?\s*(PARA|EMPRESA|DATA|VALIDADE|TIPO|MODELO|PROPOSTA\s*N[ºo°]?):/i.test(t)) return false
                        return true
                      })
                      .join("\n")}
                    className="prose-h3:text-primary prose-h3:font-semibold prose-h4:text-foreground/90"
                  />
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Approve confirmation dialog */}
      <AlertDialog open={approveOpen} onOpenChange={setApproveOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <div className="mb-2 flex justify-center">
              <div className="flex h-12 w-12 items-center justify-center rounded-full bg-[#dcfce7]">
