import type { ProposalSection, ProposalModelo } from "@/lib/proposal-types"
import { formatDateShort } from "@/lib/proposal-types"

export function clean(text: string): string {
  return text.replace(/\*\*/g, "").replace(/\*/g, "").trim()
}

export function findSection(sections: ProposalSection[], ...keywords: string[]): ProposalSection | undefined {
  return sections.find((s) =>
    keywords.some((k) => s.key.toLowerCase().includes(k) || s.title.toLowerCase().includes(k))
  )
}

export function extractSubtitulo(content: string, projeto: string): string {
  if (projeto) return projeto
  const h3 = content.match(/^###\s+(.+)$/m)
  if (h3) return clean(h3[1])
  const bold = content.match(/\*\*(.+?)\*\*/)
  if (bold) return bold[1]
  return clean(content.split("\n").find((l) => l.trim()) ?? "Projeto")
}

export function extractDescricao(content: string): string {
  const lines = content.split("\n")
  const para = lines.find((l) => {
    const t = l.trim()
    return t && !t.startsWith("#") && !t.startsWith("-") && !t.startsWith("*") && !/^\d+\./.test(t)
  })
  return clean(para ?? "")
}

export function extractDestaques(content: string): [string, string] {
  const boldLines = content
    .split("\n")
    .filter((l) => l.trim().startsWith("**") && l.trim().endsWith("**"))
    .map((l) => clean(l))
  return [boldLines[0] ?? "", boldLines[1] ?? ""]
}

export function extractFuncionalidades(content: string): string {
  const lines = content.split("\n")
  const items: string[] = []

  for (const line of lines) {
    const t = line.trim()
    const m1 = t.match(/^(\d+)\.\s+\*\*(.+?)\*\*\s*[—–:\-]\s*(.+)$/)
    if (m1) { items.push(`<div class="func-item"><p><strong>${m1[1]}. ${m1[2]}</strong> - ${clean(m1[3])}</p></div>`); continue }
    const m2 = t.match(/^(\d+)\.\s+(.+?)\s*[—–]\s*(.+)$/)
    if (m2) { items.push(`<div class="func-item"><p><strong>${m2[1]}. ${m2[2]}</strong> - ${clean(m2[3])}</p></div>`); continue }
    const m3 = t.match(/^[-*•]\s+\*\*(.+?)\*\*[:\s]+(.+)$/)
    if (m3) { items.push(`<div class="func-item"><p><strong>${items.length + 1}. ${m3[1]}</strong> - ${clean(m3[2])}</p></div>`); continue }
  }

  if (!items.length) {
    content.split("\n")
      .filter((l) => /^[-*•]\s/.test(l.trim()))
      .slice(0, 6)
      .forEach((l, i) => {
        items.push(`<div class="func-item"><p><strong>${i + 1}. ${clean(l.replace(/^[-*•]\s+/, ""))}</strong></p></div>`)
      })
  }
  return items.join("\n\n")
}

export function extractIntegracoes(content: string): string {
  const line = content.split("\n").find((l) =>
    /integr|AWS|cloud|API\s|plataforma|sistema externo/i.test(l)
  )
  if (line) return clean(line.replace(/^[-*•\d.]+\s+/, ""))
  return "Este projeto não prevê integrações com sistemas externos."
}

export function extractPrazoTotal(content: string): string {
  const m1 = content.match(/(?:prazo|total|estimado)[:\s]+(\d+(?:[,.]\d+)?\s*(?:semanas?|meses?|dias?))/i)
  if (m1) return m1[1]
  const m2 = content.match(/(\d+(?:[,.]\d+)?\s*(?:semanas?|meses?))/i)
  if (m2) return m2[1]
  return "A definir"
}

export function extractCronogramaFases(content: string): string {
  const lines = content.split("\n")
  const phases: string[] = []
  let counter = 0

  for (const line of lines) {
    const t = line.trim()
    if (!t) continue
    const m1 = t.match(/^(?:Fase\s*)?(\d+)\s*[-:]\s*(.+?)\s*\|\s*(.+)$/)
    if (m1) { phases.push(`<div class="phase"><strong>Fase ${m1[1]}:</strong> ${clean(m1[2])} – ${clean(m1[3])}</div>`); continue }
    const m2 = t.match(/^Fase\s*(\d+)\s*[-:]\s*(.+)$/)
    if (m2) { phases.push(`<div class="phase"><strong>Fase ${m2[1]}:</strong> ${clean(m2[2])}</div>`); continue }
    if (/^[-*•]\s/.test(t) && /semana|mês|mes|dias?/i.test(t)) {
      counter++
      phases.push(`<div class="phase"><strong>Fase ${counter}:</strong> ${clean(t.replace(/^[-*•]\s+/, ""))}</div>`)
    }
  }
  return phases.join("\n") || `<div class="phase"><strong>Fase 1:</strong> A definir</div>`
}

export function extractValorTotal(content: string): string {
  const totalLine = content.split("\n").find((l) => /total/i.test(l) && /R\$/i.test(l))
  if (totalLine) {
    const m = totalLine.match(/R\$\s*[\d.,]+/)
    if (m) return m[0]
  }
  const m = content.match(/R\$\s*[\d.,]+/)
  return m ? m[0] : "A definir"
}

export function extractParcelas(content: string): { v1: string; cond2: string; v2: string; cond3: string; v3: string } {
  const vals = content.match(/R\$\s*[\d.,]+/g) ?? []
  const pct = content.match(/(\d+)%/g) ?? []

  const p1 = content.match(/(?:1[aª°]?\s*parcela|assinatura)[^R\n]*R\$\s*([\d.,]+)/i)
  const p2 = content.match(/(?:2[aª°]?\s*parcela)[^R\n]*R\$\s*([\d.,]+)/i)
  const p3 = content.match(/(?:3[aª°]?\s*parcela)[^R\n]*R\$\s*([\d.,]+)/i)

  const cond2m = content.match(/(\d+\s*dias?(?:\s*após[^,\n]+)?)/i)
  const cond3m = content.match(/(?:pós.homolog|entrega final|conclusão|go.live)/i)

  return {
    v1: p1 ? `R$ ${p1[1]}` : vals[0] ?? "A definir",
    cond2: cond2m ? cond2m[1] : pct[1] ? `${pct[1]} na entrega parcial` : "30 dias após a assinatura",
    v2: p2 ? `R$ ${p2[1]}` : vals[1] ?? "A definir",
    cond3: cond3m ? cond3m[0] : pct[2] ? `${pct[2]} na entrega final` : "Pós-homologação",
    v3: p3 ? `R$ ${p3[1]}` : vals[2] ?? "A definir",
  }
}

export function extractEntregaveis(content: string): string {
  const deliverableKeywords = /protótipo|figma|documentação|código|repositório|sistema|produção|api\s|deploy|fonte/i
  const items = content
    .split("\n")
    .filter((l) => /^[-*•]\s/.test(l.trim()) && deliverableKeywords.test(l))
    .map((l) => `<li>${clean(l.replace(/^[-*•]\s+/, ""))}</li>`)

  if (items.length) return items.join("\n                    ")
  return [
    "<li>Protótipos de Alta Fidelidade (Figma).</li>",
    "<li>Documentação Funcional.</li>",
    "<li>Documentação Técnica.</li>",
    "<li>Código Fonte Completo (repositório Git).</li>",
    "<li>Sistema em Produção.</li>",
  ].join("\n                    ")
}

export function buildProposalTokens(params: {
  empresa: string
  para: string | undefined
  projeto: string | undefined
  modeloTrabalho: ProposalModelo | undefined
  dataCriacao: number
  sections: ProposalSection[]
}): Record<string, string> {
  const { empresa, para, projeto, modeloTrabalho, dataCriacao, sections } = params

  const sobreSection     = findSection(sections, "sobre", "objetivo", "projeto", "descricao")
  const escopoSection    = findSection(sections, "escopo", "funcionalidade", "requisito", "solucao")
  const cronoSection     = findSection(sections, "cronograma", "timeline", "prazo", "fase")
  const investSection    = findSection(sections, "investimento", "valor", "preco", "precificacao")
  const condicoesSection = findSection(sections, "condicao", "pagamento", "comercial", "financeiro")
  const entregaSection   = findSection(sections, "entregavel", "entrega", "deliverable")

  const sobreContent  = sobreSection?.content ?? ""
  const escopoContent = escopoSection?.content ?? sobreContent
  const parcelas      = extractParcelas(condicoesSection?.content ?? investSection?.content ?? "")
  const [destaque1, destaque2] = extractDestaques(sobreContent + "\n" + escopoContent)

  return {
    NOME_CLIENTE:       empresa || "—",
    DESTINATARIO:       para || empresa || "—",
    DATA:               formatDateShort(dataCriacao),
    TIPO_PROJETO:       modeloTrabalho && modeloTrabalho !== "Vazio" ? modeloTrabalho : "Escopo Fechado",
    SUBTITULO_PROJETO:  extractSubtitulo(sobreContent, projeto ?? ""),
    DESCRICAO_PROJETO:  extractDescricao(sobreContent),
    DESTAQUE_1:         destaque1 || extractDescricao(escopoContent),
    DESTAQUE_2:         destaque2 || "Solução desenvolvida com as melhores práticas de engenharia de software.",
    FUNCIONALIDADES:    extractFuncionalidades(escopoContent || sobreContent),
    INTEGRACOES_TEXTO:  extractIntegracoes(escopoContent),
    PRAZO_TOTAL:        extractPrazoTotal(cronoSection?.content ?? ""),
    CRONOGRAMA_FASES:   extractCronogramaFases(cronoSection?.content ?? ""),
    VALOR_TOTAL:        extractValorTotal(investSection?.content ?? ""),
    PARCELA_1_VALOR:    parcelas.v1,
    PARCELA_2_CONDICAO: parcelas.cond2,
    PARCELA_2_VALOR:    parcelas.v2,
    PARCELA_3_CONDICAO: parcelas.cond3,
    PARCELA_3_VALOR:    parcelas.v3,
    ENTREGAVEIS:        extractEntregaveis(entregaSection?.content ?? escopoContent),
  }
}

# Guia do Template Dinâmico de Propostas

## Visão Geral

O `proposta-template-dinamico.html` é um sistema flexível para geração automática de propostas comerciais que se adapta ao volume de conteúdo, similar ao comportamento do Google Docs ou Word.

## Principais Funcionalidades

### ✅ Layout Dinâmico
- **Quebras automáticas** de página baseadas no conteúdo
- **Numeração automática** de páginas via CSS counters
- **Background fixo** em todas as páginas
- **Footer consistente** em todas as páginas

### ✅ Sistema de Variáveis
- **{{VARIÁVEL}}** — placeholders para substituição dinâmica
- **Seções modulares** — adicione/remova conforme necessário
- **Conteúdo flexível** — expande automaticamente

### ✅ Controle de Fluxo
- **CSS Grid/Flexbox** para layout responsivo
- **break-inside: avoid** para evitar quebras indesejadas
- **orphans/widows** para controle tipográfico
- **page-break controls** otimizados para impressão

## Variáveis Disponíveis

### Informações da Capa
```
{{NOME_CLIENTE}}           // Nome do cliente (título principal)
{{NOME_EMPRESA}}           // Nome da sua empresa
{{TITULO_PROPOSTA}}        // Ex: "Proposta Comercial"
{{DATA_PROPOSTA}}          // Ex: "27/03/2026"
{{DIAS_VALIDADE}}          // Ex: "30"
{{CLIENTE_EMPRESA}}        // Ex: "Agência XPTO"
{{TIPO_ESCOPO}}            // Ex: "Escopo fechado"
{{INFORMACOES_ADICIONAIS_CAPA}}  // Informações extras da capa
{{CONTEUDO_INICIAL_CAPA}}  // Conteúdo que aparece na capa
```

### Conteúdo Principal
```
{{TITULO_SOBRE_EMPRESA}}   // Ex: "Sobre a Wa Project"
{{DESCRICAO_EMPRESA}}      // Descrição da empresa
{{SECAO_SERVICOS}}         // Bloco HTML com lista de serviços
{{TITULO_CLIENTES}}        // Ex: "Nossos Clientes"
{{LISTA_CLIENTES}}         // Bloco HTML com lista de clientes
```

### Projeto e Funcionalidades
```
{{TITULO_PROJETO}}         // Ex: "Sobre o Projeto"
{{SUBTITULO_PROJETO}}      // Subtítulo do projeto
{{DESCRICAO_PROJETO}}      // Descrição completa (pode ter múltiplos parágrafos)
{{TITULO_FUNCIONALIDADES}} // Ex: "Funcionalidades"
{{LISTA_FUNCIONALIDADES}}  // Bloco HTML com funcionalidades
```

### Execução e Investimento
```
{{TITULO_MODELO_TRABALHO}} // Ex: "Modelo de Trabalho"
{{TITULO_EQUIPE}}          // Ex: "Equipe"
{{TITULO_CRONOGRAMA}}      // Ex: "Cronograma"
{{TITULO_INVESTIMENTO}}    // Ex: "Investimento"
{{VALOR_TOTAL}}            // Ex: "<p class="investment-total">R$ 20.000</p>"
{{CONDICOES_PAGAMENTO}}    // Bloco HTML com condições
```

## Como Usar

### 1. Substituição Simples
```javascript
// Exemplo de uso básico
let template = document.documentElement.outerHTML;
template = template.replace(/\{\{NOME_CLIENTE\}\}/g, "Easy Salon");
template = template.replace(/\{\{TITULO_PROPOSTA\}\}/g, "Proposta Comercial");
```

### 2. Substituição em Lote
```javascript
const variables = {
    'NOME_CLIENTE': 'Easy Salon',
    'DATA_PROPOSTA': '30/03/2026',
    'VALOR_TOTAL': '<p class="investment-total">Investimento total: R$ 25.000</p>',
    'LISTA_FUNCIONALIDADES': `
        <div class="func-item">
            <p><strong>1. Dashboard Administrativo</strong> - Interface completa...</p>
        </div>
        <div class="func-item">
            <p><strong>2. Sistema de Agendamento</strong> - Calendário integrado...</p>
        </div>
    `
};

let html = template;
for (const [key, value] of Object.entries(variables)) {
    html = html.replace(new RegExp(`\\{\\{${key}\\}\\}`, 'g'), value);
}
```

### 3. Conteúdo HTML Complexo
```javascript
// Para listas e conteúdo estruturado
const servicosHTML = `
    <h3>Nossos serviços:</h3>
    <ul>
        <li>Desenvolvimento de Software.</li>
        <li>Desenvolvimento de Aplicativos.</li>
        <li>Soluções de Inteligência Artificial.</li>
        <li>Alocação de Profissionais.</li>
    </ul>
`;

variables['SECAO_SERVICOS'] = servicosHTML;
```

## Estrutura CSS Responsiva

### Classes Principais
- `.content-section` — seção de conteúdo com controle de quebra
- `.content-section.allow-break` — permite quebra dentro da seção
- `.func-item` — item de funcionalidade (evita quebra)
- `.team-role` — membro da equipe (evita quebra)
- `.phase` — fase do projeto (evita quebra)

### Controle de Quebras
```css
/* Evita quebra dentro do elemento */
.no-break {
    break-inside: avoid-page;
    page-break-inside: avoid;
}

/* Força quebra antes do elemento */
.force-break {
    break-before: page;
    page-break-before: always;
}
```

## Otimizações

### Para Impressão
- Background fixo otimizado
- Controles de orphans/widows
- Numeração automática de páginas
- Footer consistente

### Para Geração Automática
```javascript
// Função opcional para otimizar quebras
// Adicione ?optimize=true na URL para ativar
if (window.location.search.includes('optimize=true')) {
    // Sistema automático de otimização ativado
}
```

### Depuração
```javascript
// Ver todas as variáveis utilizadas
console.log(getTemplateVariables());
// Output: ['{{NOME_CLIENTE}}', '{{TITULO_PROPOSTA}}', ...]
```

## Exemplo de Integração

```javascript
// Sistema gerador de propostas
class PropostaGenerator {
    constructor(templatePath) {
        this.template = this.loadTemplate(templatePath);
    }

    async generate(dadosProposta) {
        let html = this.template;

        // Substituir variáveis simples
        for (const [key, value] of Object.entries(dadosProposta)) {
            html = html.replace(
                new RegExp(`\\{\\{${key}\\}\\}`, 'g'),
                value || ''
            );
        }

        // Remover variáveis não utilizadas
        html = html.replace(/\{\{[A-Z_]+\}\}/g, '');

        return html;
    }
}

// Uso
const generator = new PropostaGenerator('proposta-template-dinamico.html');
const proposta = await generator.generate({
    NOME_CLIENTE: 'Empresa XYZ',
    VALOR_TOTAL: '<p class="investment-total">R$ 50.000</p>',
    // ... outras variáveis
});
```

## Vantagens do Sistema

1. **Flexibilidade Total** — adapta-se a qualquer volume de conteúdo
2. **Layout Consistente** — mantém design profissional independente do tamanho
3. **Quebras Inteligentes** — evita elementos órfãos ou viúvos
4. **Numeração Automática** — não precisa controlar manualmente
5. **Reutilização** — um template para todas as propostas
6. **Manutenção** — mudanças no template afetam todas as propostas

## Suporte a Navegadores

- ✅ Chrome/Edge (print-ready)
- ✅ Firefox (print-ready)
- ✅ Safari (print-ready)
- ✅ Puppeteer/Playwright (PDF generation)

