"use client"

import { use, useState, useCallback, useRef, useEffect } from "react"
import { callProposalGeneratorAction } from "@/app/actions/severino"
import { useRouter } from "next/navigation"
import { useLeads } from "@/contexts/leads-context"
import { useBreadcrumbSetter } from "@/hooks/use-breadcrumb-setter"
import { Button } from "@/components/ui/button"
import { Textarea } from "@/components/ui/textarea"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"
import {
  BrainCircuit, SendHorizonal, Paperclip, X, Plus,
  FileText, Download, Database, Loader2,
} from "lucide-react"
import { toast } from "sonner"
import { ProposalEditorSkeleton } from "@/components/content-skeleton"
import { MarkdownRenderer } from "@/components/markdown-renderer"
import { buildProposalTokens } from "@/lib/proposal-pdf-utils"

// Normaliza linhas que usam emoji como marcador (✅ ❌ etc.) para itens de lista markdown reais.
// Sem isso, linhas consecutivas separadas apenas por \n colapsam num único parágrafo no ReactMarkdown.
function normalizeListLines(content: string): string {
  return content
    .split("\n")
    .map((line) => {
      const trimmed = line.trimStart()
      if (/^[✅❌✓✗•→]/.test(trimmed) && !trimmed.startsWith("- ")) {
        return `- ${trimmed}`
      }
      return line
    })
    .join("\n")
}

function parseMarkdownSections(markdown: string): { key: string; title: string; content: string }[] {
  const sections: { key: string; title: string; content: string }[] = []
  const lines = markdown.split("\n")
  let currentTitle = ""
  let currentContent: string[] = []

  for (const line of lines) {
    const h2Match = line.match(/^## (.+)$/)
    if (h2Match) {
      if (currentTitle) {
        sections.push({
          key: currentTitle.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, ""),
          title: currentTitle,
          content: normalizeListLines(currentContent.join("\n").trim()),
        })
      }
      currentTitle = h2Match[1].trim()
      currentContent = []
    } else if (currentTitle) {
      currentContent.push(line)
    }
  }

  if (currentTitle && currentContent.length > 0) {
    sections.push({
      key: currentTitle.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, ""),
      title: currentTitle,
      content: normalizeListLines(currentContent.join("\n").trim()),
    })
  }

  return sections
}

// ---- Main Page ----

export default function LeadProposalEditorPage({
  params,
}: {
  params: Promise<{ leadId: string; propostaId: string }>
}) {
  const { leadId, propostaId } = use(params)
  const router = useRouter()
  const { getLead, getLeadProposal, updateLeadProposal, isLoading } = useLeads()

  const lead = getLead(leadId)
  const proposal = getLeadProposal(propostaId)
  const proposalRef = useRef(proposal)
  proposalRef.current = proposal

  useBreadcrumbSetter([
    { label: "Leads", href: "/dashboard/leads" },
    { label: lead?.titulo ?? "Lead", href: `/dashboard/leads/${leadId}` },
    { label: proposal?.nome ?? "Proposta Comercial" },
  ])

  const [isProcessing, setIsProcessing] = useState(false)
  const [downloading, setDownloading] = useState(false)
  const [highlightedSections, setHighlightedSections] = useState<Set<string>>(new Set())
  const [clarificationQuestions, setClarificationQuestions] = useState<string[]>([])
  const [localLoading, setLocalLoading] = useState(true)

  useEffect(() => {
    const t = setTimeout(() => setLocalLoading(false), 500)
    return () => clearTimeout(t)
  }, [])

  const handleDownloadPDF = async () => {
    if (!proposal || proposal.proposalContent.length === 0) return
    setDownloading(true)
    try {
      const res = await fetch("/proposta-template.html")
      if (!res.ok) throw new Error("Template não encontrado")
      let html = await res.text()

      const tokens = buildProposalTokens({
        empresa: lead?.titulo ?? "",
        para: undefined,
        projeto: proposal.nome,
        modeloTrabalho: lead?.modeloTrabalho,
        dataCriacao: proposal.dataCriacao,
        sections: proposal.proposalContent,
      })

      for (const [key, value] of Object.entries(tokens)) {
        html = html.replaceAll(`{{${key}}}`, value)
      }

      const win = window.open("", "_blank")
      if (!win) {
        toast.error("Pop-up bloqueado. Permita pop-ups para este site e tente novamente.")
        return
      }
      win.document.open()
      win.document.write(html)
      win.document.close()
      win.addEventListener("load", () => win.print())
      setTimeout(() => { if (win && !win.closed) win.print() }, 800)

      toast.success("Proposta aberta! Selecione 'Salvar como PDF' com margens 'Nenhuma'.")
    } catch (err) {
      console.error("[LeadProposalPage] PDF error:", err)
      toast.error("Erro ao gerar o PDF.")
    } finally {
      setDownloading(false)
    }
  }

  const handleSendMessage = useCallback(
    async (content: string, fileName?: string) => {
      const current = proposalRef.current
      if (!current) return

      const userMsg = { id: `u-${Date.now()}`, role: "user" as const, content, fileName }
      const newHistory = [...current.conversationHistory, userMsg]

