          {downloading ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Download className="h-3.5 w-3.5" />}
          Imprimir / Salvar PDF
        </Button>
      </div>

      <div className="flex-1 overflow-y-auto bg-background pl-4 pr-1.5 py-4 sidebar-scroll">
        {sections.length === 0 ? (
          <div className="flex h-full flex-col items-center justify-center rounded-lg border-2 border-dashed border-border p-6">
            <FileText className="h-12 w-12 text-muted-foreground/30 mb-4" />
            <p className="text-sm font-medium text-muted-foreground text-center">A proposta será gerada aqui conforme você fornecer informações ao assistente.</p>
            <p className="text-xs text-muted-foreground mt-1">Comece a conversa ao lado!</p>
          </div>
        ) : (
          <div className="space-y-4 rounded-lg border border-border/50 bg-muted/50 p-4">
            <div className="text-center border-b pb-4">
              <h1 className="text-lg font-bold text-foreground">{title}</h1>
              <p className="text-xs text-muted-foreground mt-1">Gerada em {new Date().toLocaleDateString("pt-BR")}</p>
            </div>
            {sections.map((section) => (
              <div key={section.key} className={cn("rounded-md p-3 transition-colors duration-500", highlightedSections.has(section.key) ? "bg-[#fef9c3]" : "bg-transparent")}>
                <h3 className="text-sm font-bold text-foreground mb-2">{section.title}</h3>
                <MarkdownRenderer content={section.content} className="prose-sm prose-h3:text-primary prose-h3:font-semibold" />
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

