// Normaliza linhas que usam emoji como marcador (✅ ❌ etc.) para itens de lista markdown reais.
// Sem isso, linhas consecutivas separadas apenas por \n colapsam num único parágrafo no ReactMarkdown.
function normalizeListLines(content: string): string {
  return content
    .split("\n")
    .map((line) => {
      const trimmed = line.trimStart()
      if (/^[✅❌✓✗•→]/.test(trimmed) && !trimmed.startsWith("- ")) {
        return `- ${trimmed}`
      }
      return line
    })
    .join("\n")
}

function parseMarkdownSections(markdown: string): { key: string; title: string; content: string }[] {
  const sections: { key: string; title: string; content: string }[] = []
  const lines = markdown.split("\n")
  let currentTitle = ""
  let currentContent: string[] = []

  for (const line of lines) {
    const h2Match = line.match(/^## (.+)$/)
    if (h2Match) {
      if (currentTitle) {
        sections.push({
          key: currentTitle.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, ""),
          title: currentTitle,
          content: normalizeListLines(currentContent.join("\n").trim()),
        })
      }
      currentTitle = h2Match[1].trim()
      currentContent = []
    } else if (currentTitle) {
      currentContent.push(line)
    }
  }

  if (currentTitle && currentContent.length > 0) {
    sections.push({
      key: currentTitle.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, ""),
      title: currentTitle,
      content: normalizeListLines(currentContent.join("\n").trim()),
    })
  }

  return sections
}

