import { describe, it, expect } from "vitest"
import {
  clean,
  findSection,
  gerarFuncionalidadesHTML,
  gerarFasesHTML,
  gerarEntregaveisHTML,
  gerarServicosHTML,
  gerarListaClientesHTML,
  gerarCondicoesPagamentoHTML,
  extractValorTotal,
  extractSubtitulo,
  extractDescricao,
  extractPrazoTotal,
  buildProposalTokens,
} from "./proposal-pdf-utils"
import type { ProposalSection, ProposalModelo } from "./proposal-types"

// ── clean ──────────────────────────────────────────────────────────────────

describe("clean", () => {
  it("deve remover marcadores **bold**", () => {
    expect(clean("**Texto em negrito**")).toBe("Texto em negrito")
  })
  it("deve remover marcadores *italic*", () => {
    expect(clean("*Texto itálico*")).toBe("Texto itálico")
  })
  it("deve fazer trim de espaços", () => {
    expect(clean("  texto  ")).toBe("texto")
  })
  it("deve retornar string vazia quando vazio", () => {
    expect(clean("")).toBe("")
  })
})

// ── findSection ────────────────────────────────────────────────────────────

describe("findSection", () => {
  const sections: ProposalSection[] = [
    { key: "sobre-o-projeto", title: "Sobre o Projeto", content: "conteudo A" },
    { key: "escopo",          title: "Escopo dos Serviços", content: "conteudo B" },
    { key: "cronograma",      title: "Cronograma", content: "conteudo C" },
    { key: "investimento",    title: "Investimento", content: "conteudo D" },
  ]

  it("deve encontrar seção por keyword no key", () => {
    expect(findSection(sections, "escopo")?.content).toBe("conteudo B")
  })
  it("deve encontrar seção por keyword no title", () => {
    expect(findSection(sections, "cronograma")?.content).toBe("conteudo C")
  })
  it("deve retornar undefined quando não encontra", () => {
    expect(findSection(sections, "inexistente")).toBeUndefined()
  })
  it("deve usar o primeiro match quando múltiplas keywords batem", () => {
    expect(findSection(sections, "investimento", "escopo")?.key).toBe("escopo")
  })
})

// ── gerarFuncionalidadesHTML ───────────────────────────────────────────────

describe("gerarFuncionalidadesHTML", () => {
  it("deve converter padrão '1. **Nome** — Desc' para HTML com func-item", () => {
    const content = "1. **Formulário de Captura** — Tela inicial com campos de Nome e Email."
    const result = gerarFuncionalidadesHTML(content)
    expect(result).toContain('<div class="func-item">')
    expect(result).toContain("<strong>1. Formulário de Captura</strong>")
    expect(result).toContain("Tela inicial com campos de Nome e Email.")
  })

  it("deve converter padrão '1. Nome — Desc' para HTML", () => {
    const content = "1. Quiz Interativo — Interface para TV touch."
    const result = gerarFuncionalidadesHTML(content)
    expect(result).toContain('<div class="func-item">')
    expect(result).toContain("<strong>1. Quiz Interativo</strong>")
    expect(result).toContain("Interface para TV touch.")
  })

  it("deve converter padrão '- **Nome**: Desc' para HTML numerado", () => {
    const content = "- **Exportação de Dados**: Gera arquivo Excel ao final."
    const result = gerarFuncionalidadesHTML(content)
    expect(result).toContain('<div class="func-item">')
    expect(result).toContain("<strong>1. Exportação de Dados</strong>")
    expect(result).toContain("Gera arquivo Excel ao final.")
  })

  it("deve usar fallback de bullets simples quando nenhum padrão bate", () => {
    const content = "- Feature A\n- Feature B\n- Feature C"
    const result = gerarFuncionalidadesHTML(content)
    expect(result).toContain("Feature A")
    expect(result).toContain('<div class="func-item">')
    expect(result).toContain("<strong>1. Feature A</strong>")
  })

  it("deve gerar HTML vazio quando não há funcionalidades", () => {
    const result = gerarFuncionalidadesHTML("")
    expect(result).toBe("")
  })
})

// ── gerarFasesHTML ─────────────────────────────────────────────────────────

describe("gerarFasesHTML", () => {
  it("deve converter padrão 'Fase N - Desc | Período' para HTML com phase class", () => {
    const content = "Fase 1 - Planejamento | Semanas 1-2\nFase 2 - Desenvolvimento | Semanas 3-8"
    const result = gerarFasesHTML(content)
    expect(result).toContain('<div class="phase">')
    expect(result).toContain("<strong>Fase 1:</strong>")
    expect(result).toContain("Planejamento – Semanas 1-2")
    expect(result).toContain("<strong>Fase 2:</strong>")
    expect(result).toContain("Desenvolvimento – Semanas 3-8")
  })

  it("deve converter padrão 'Fase N - Desc' sem período para HTML", () => {
    const content = "Fase 3 - Homologação e Go-Live"
    const result = gerarFasesHTML(content)
    expect(result).toContain('<div class="phase">')
    expect(result).toContain("<strong>Fase 3:</strong>")
    expect(result).toContain("Homologação e Go-Live")
  })

  it("deve numerar bullets com prazo automaticamente", () => {
    const content = "- Planejamento e arquitetura: 2 semanas\n- Backend e APIs: 5 semanas"
    const result = gerarFasesHTML(content)
    expect(result).toContain("<strong>Fase 1:</strong>")
    expect(result).toContain("<strong>Fase 2:</strong>")
  })

  it("deve retornar fallback quando conteúdo está vazio", () => {
    const result = gerarFasesHTML("")
    expect(result).toContain('<div class="phase">')
    expect(result).toContain("A definir")
  })
})

// ── gerarEntregaveisHTML ───────────────────────────────────────────────────

describe("gerarEntregaveisHTML", () => {
  it("deve extrair bullets com keywords de entregável para <ul><li>", () => {
    const content = "- Protótipos no Figma\n- Código fonte no repositório Git\n- Sistema em produção"
    const result = gerarEntregaveisHTML(content)
    expect(result).toContain("<ul>")
    expect(result).toContain("<li>Protótipos no Figma</li>")
    expect(result).toContain("<li>Código fonte no repositório Git</li>")
    expect(result).toContain("<li>Sistema em produção</li>")
    expect(result).toContain("</ul>")
  })

  it("deve retornar lista padrão quando nenhum bullet tem keyword de entregável", () => {
    const result = gerarEntregaveisHTML("Texto sem keywords de entregável.")
    expect(result).toContain("Protótipos de Alta Fidelidade (Figma)")
    expect(result).toContain("Sistema em Produção")
    expect(result).toContain("<ul>")
    expect(result).toContain("</ul>")
  })

  it("deve filtrar apenas bullets com keywords relevantes", () => {
    const content = "- Item irrelevante\n- Protótipos finais\n- Outro item\n- Documentação completa"
    const result = gerarEntregaveisHTML(content)
    expect(result).toContain("Protótipos finais")
    expect(result).toContain("Documentação completa")
    expect(result).not.toContain("Item irrelevante")
  })
})

// ── gerarServicosHTML & gerarListaClientesHTML ────────────────────────────

describe("gerarServicosHTML", () => {
  it("deve retornar HTML estruturado com lista de serviços", () => {
    const result = gerarServicosHTML()
    expect(result).toContain("<h3>Nossos serviços:</h3>")
    expect(result).toContain("Desenvolvimento de Software")
    expect(result).toContain("Soluções de Inteligência Artificial")
    expect(result).toContain("<ul>")
    expect(result).toContain("</ul>")
  })
})

describe("gerarListaClientesHTML", () => {
  it("deve retornar HTML estruturado com lista de clientes", () => {
    const result = gerarListaClientesHTML()
    expect(result).toContain("Easy Salon")
    expect(result).toContain("Sistema de gestão para salões de beleza")
    expect(result).toContain("<ul>")
    expect(result).toContain("</ul>")
  })
})

// ── gerarCondicoesPagamentoHTML ────────────────────────────────────────────

describe("gerarCondicoesPagamentoHTML", () => {
  it("deve extrair 3 parcelas nomeadas com R$ para HTML estruturado", () => {
    const content = [
      "1ª parcela: R$ 6.667 na assinatura",
      "2ª parcela: R$ 6.667 após 30 dias",
      "3ª parcela: R$ 6.666 pós-homologação",
    ].join("\n")
    const result = gerarCondicoesPagamentoHTML(content)
    expect(result).toContain('<div class="payment-condition">')
    expect(result).toContain("<strong>1ª parcela:</strong> R$ 6.667")
    expect(result).toContain("<strong>2ª parcela:</strong> R$ 6.667")
    expect(result).toContain("<strong>3ª parcela:</strong> R$ 6.666")
    expect(result).toContain("pós-homolog")
  })

